#!/usr/bin/env node
// PreToolUse hook: injects fileContent + fromDiskDigest for Theia save/commit tools.
const crypto = require('crypto');
const fs = require('fs');
const path = require('path');

let data = '';
process.stdin.on('data', chunk => (data += chunk));
process.stdin.on('end', () => {
  let parsed;
  try {
    parsed = JSON.parse(data);
  } catch {
    process.exit(0);
  }

  const toolName = parsed.tool_name || '';
  const input = parsed.tool_input || {};

  if (toolName === 'mcp__theia__save_artifact') {
    const clonePath = input.clonePath;
    const filePath = input.filePath;
    if (!clonePath || !filePath) { process.exit(0); }

    const fullPath = path.join(clonePath, filePath);
    let content;
    try {
      content = fs.readFileSync(fullPath, 'utf8');
    } catch (e) {
      process.stderr.write(`hook: cannot read ${fullPath}: ${e.message}\n`);
      process.exit(0);
    }
    const digest = 'sha256:' + crypto.createHash('sha256').update(content).digest('hex');
    input.fileContent = content;
    input.fromDiskDigest = digest;

    const procPaths = input.processFilePaths || [];
    if (procPaths.length > 0) {
      input.processFiles = procPaths.map(p => {
        const pPath = path.join(clonePath, p);
        const pContent = fs.readFileSync(pPath, 'utf8');
        const pDigest = 'sha256:' + crypto.createHash('sha256').update(pContent).digest('hex');
        return { path: p, content: pContent, fromDiskDigest: pDigest };
      });
      delete input.processFilePaths;
    }

    process.stdout.write(JSON.stringify({ tool_input: input }));
    return;
  }

  if (toolName === 'mcp__theia__commit_process_files') {
    const clonePath = input.clonePath;
    const filePaths = input.filePaths || [];
    if (!clonePath || filePaths.length === 0) { process.exit(0); }

    input.files = filePaths.map(p => {
      const pPath = path.join(clonePath, p);
      const pContent = fs.readFileSync(pPath, 'utf8');
      const pDigest = 'sha256:' + crypto.createHash('sha256').update(pContent).digest('hex');
      return { path: p, content: pContent, fromDiskDigest: pDigest };
    });
    delete input.filePaths;

    process.stdout.write(JSON.stringify({ tool_input: input }));
    return;
  }

  process.exit(0);
});
